const raw = $input.first().json.response || '';
let prompts;
try {
  const match = raw.match(/```json\n([\s\S]*?)\n```/) || raw.match(/(\{[\s\S]*\})/);
  prompts = JSON.parse(match ? (match[1] || match[0]) : raw);
} catch(e) {
  prompts = {
    run_id: new Date().toISOString().slice(0,10) + '-001',
    research_prompt: 'Find a trending how-to topic with affiliate potential.',
    writer_prompt: 'Write a 2800-word how-to article for beginners.',
    humanizer_prompt: 'Rewrite this article to sound like a human expert blogger.',
    seo_prompt: 'Generate SEO metadata, tags, slug, and affiliate links.',
    image_prompt: 'bright educational blog hero image minimal style',
    social_prompt: 'Create viral posts for FB IG TikTok Pinterest YT Shorts.',
    qc_prompt: 'Review content for quality, SEO, and monetization compliance.',
    comment_prompt: 'Moderate and respond to blog comments professionally.',
    parse_error: e.message
  };
}
prompts.generated_at = new Date().toISOString();
return [{ json: prompts }];

const raw = $input.first().json.response || '';
let topic;
try {
  const match = raw.match(/```json\n([\s\S]*?)\n```/) || raw.match(/(\{[\s\S]*\})/);
  topic = JSON.parse(match ? (match[1] || match[0]) : raw);
} catch(e) {
  topic = {
    topic: 'How to Start Affiliate Marketing as a Complete Beginner',
    primary_keyword: 'affiliate marketing for beginners',
    secondary_keywords: ['make money affiliate marketing','affiliate programs','passive income'],
    lsi_keywords: ['commission','product promotion','referral link'],
    search_intent: 'informational',
    estimated_volume: 'high',
    competition: 'medium',
    affiliate_products: [
      { name: 'CB University', network: 'ClickBank', commission: '75%', affiliate_link: 'YOUR_LINK', placement_suggestion: 'after intro' },
      { name: 'DS24 Course', network: 'Digistore24', commission: '50%', affiliate_link: 'YOUR_DS24_LINK', placement_suggestion: 'mid article' }
    ],
    monetization_score: 9,
    parse_error: e.message
  };
}
topic.run_id = $('Parse Prompt Package').item.json.run_id;
topic.validated_at = new Date().toISOString();
return [{ json: topic }];

const seoRaw = $('Agent 4: SEO & Monetization').item.json.response || '';
const humanizedContent = $('Agent 3: Humanizer').item.json.response || '';
const topicData = $('Parse & Validate Topic').item.json;

let seoData;
try {
  const match = seoRaw.match(/```json\n([\s\S]*?)\n```/) || seoRaw.match(/(\{[\s\S]*\})/);
  seoData = JSON.parse(match ? (match[1] || match[0]) : seoRaw);
} catch(e) {
  seoData = {
    seo: { title: topicData.topic, meta_description: '', slug: topicData.primary_keyword.replace(/ /g,'-'), tags: topicData.secondary_keywords || [], categories: ['Tutorials'], focus_keyword: topicData.primary_keyword, schema_type: 'HowTo' },
    monetization: { disclosure: 'This post contains affiliate links.', adsense_zones: [], affiliate_ctas: [] },
    parse_error: e.message
  };
}

// Build final assembled article with all zones injected
let finalContent = seoData.monetization.disclosure + '\n\n' + humanizedContent;

// Replace ad zone markers with shortcode-style placeholders
finalContent = finalContent
  .replace('[AD_ZONE_TOP]', '<!-- ADSENSE_TOP_AD -->')
  .replace('[AD_ZONE_MID]', '<!-- ADSENSE_MID_AD --> <!-- ADSTERRA_NATIVE -->')
  .replace('[AD_ZONE_BOTTOM]', '<!-- ADSENSE_BOTTOM_AD -->');

// Replace affiliate CTA markers
(seoData.monetization.affiliate_ctas || []).forEach(cta => {
  const marker = `[AFFILIATE_CTA: ${cta.product}`;
  const buttonHtml = `<div class="affiliate-cta" style="background:#f8f9fa;padding:20px;border-left:4px solid ${cta.button_color || '#FF6B35'};margin:20px 0">
    <p><strong>${cta.anchor_text}</strong></p>
    <a href="${cta.affiliate_link}" target="_blank" rel="noopener" style="background:${cta.button_color || '#FF6B35'};color:white;padding:12px 24px;text-decoration:none;border-radius:4px;display:inline-block">${cta.button_text}</a>
  </div>`;
  finalContent = finalContent.replace(new RegExp(`\\[AFFILIATE_CTA: ${cta.product}[^\\]]*\\]`, 'g'), buttonHtml);
});

const wpPayload = {
  title: seoData.seo.title || topicData.topic,
  content: finalContent,
  slug: seoData.seo.slug,
  status: 'draft',
  tags: seoData.seo.tags || [],
  categories: seoData.seo.categories || ['Tutorials'],
  meta_description: seoData.seo.meta_description,
  focus_keyword: seoData.seo.focus_keyword,
  schema_markup: seoData.schema_markup || {},
  og_title: seoData.seo.og_title || seoData.seo.title,
  og_description: seoData.seo.og_description || seoData.seo.meta_description,
  image_alt_texts: seoData.seo.image_alt_texts || [],
  monetization_summary: {
    affiliate_products: topicData.affiliate_products?.length || 0,
    ad_zones: 3,
    networks: [...new Set((topicData.affiliate_products || []).map(p => p.network))]
  },
  run_id: topicData.run_id
};

return [{ json: wpPayload }];

// Build Pexels API search query from topic data
const topic = $('Parse & Validate Topic').item.json;
const wpPayload = $('Assemble Final Article').item.json;

// Extract image suggestions from content
const imageMatches = wpPayload.content.match(/\[IMAGE_SUGGESTION: ([^\]]+)\]/g) || [];
const imageSuggestions = imageMatches.map(m => m.replace('[IMAGE_SUGGESTION: ', '').replace(']', ''));

// Build smart search queries
const queries = [
  imageSuggestions[0] || topic.primary_keyword,
  topic.topic.replace('How to ', '').split(' ').slice(0,3).join(' '),
  topic.secondary_keywords?.[0] || 'tutorial learning'
];

return [{ json: { 
  queries,
  primary_query: queries[0],
  topic_keyword: topic.primary_keyword,
  run_id: topic.run_id
}}];

const pexelsData = $('Search Pexels').item.json;
const pixabayData = $('Search Pixabay (Fallback)').item.json;
const queryData = $('Build Image Queries').item.json;

let imageUrl = null;
let imageSource = null;
let photographer = null;
let imagePageUrl = null;

// Try Pexels first
if (pexelsData.photos && pexelsData.photos.length > 0) {
  const photo = pexelsData.photos[0];
  imageUrl = photo.src.large2x || photo.src.large;
  imageSource = 'pexels';
  photographer = photo.photographer;
  imagePageUrl = photo.url;
}
// Try Pixabay as fallback
else if (pixabayData.hits && pixabayData.hits.length > 0) {
  const photo = pixabayData.hits[0];
  imageUrl = photo.largeImageURL || photo.webformatURL;
  imageSource = 'pixabay';
  photographer = photo.user;
  imagePageUrl = photo.pageURL;
}

// Set flag for Stable Diffusion fallback
const needsGeneration = !imageUrl;

return [{ json: {
  imageUrl,
  imageSource,
  photographer,
  imagePageUrl,
  needsGeneration,
  query: queryData.primary_query,
  alt_text: `${queryData.topic_keyword} - HowTo-Genie`,
  credit_text: imageSource ? `Photo by ${photographer} on ${imageSource}` : null
}}];

