const raw = $input.first().json.response || '';
let posts;
try {
  const match = raw.match(/```json\n([\s\S]*?)\n```/) || raw.match(/(\{[\s\S]*\})/);
  posts = JSON.parse(match ? (match[1] || match[0]) : raw);
} catch(e) {
  posts = { parse_error: e.message, raw_response: raw.substring(0, 500) };
}

const blogUrl = $('Publish to WordPress').item.json.link || 'https://howtogenie.com';

// Return all platforms as separate items for parallel posting
return [
  { json: { platform: 'facebook', content: posts.facebook?.post + '\n\n' + posts.facebook?.hashtags?.join(' '), blog_url: blogUrl, raw: posts.facebook }},
  { json: { platform: 'instagram', content: posts.instagram?.caption + '\n\n' + posts.instagram?.hashtags?.join(' '), blog_url: blogUrl, raw: posts.instagram }},
  { json: { platform: 'tiktok', content: posts.tiktok?.script, caption: posts.tiktok?.caption, hashtags: posts.tiktok?.hashtags, blog_url: blogUrl, raw: posts.tiktok }},
  { json: { platform: 'pinterest', content: posts.pinterest?.description, title: posts.pinterest?.title, blog_url: blogUrl, raw: posts.pinterest }},
  { json: { platform: 'youtube_shorts', content: posts.youtube_shorts?.script, title: posts.youtube_shorts?.title, description: posts.youtube_shorts?.description, blog_url: blogUrl, raw: posts.youtube_shorts }},
  { json: { platform: 'reels_script', content: JSON.stringify(posts.reels_universal_script, null, 2), blog_url: blogUrl, raw: posts.reels_universal_script }}
];

const raw = $input.first().json.response || '';
let decisions;
try {
  const match = raw.match(/```json\n([\s\S]*?)\n```/) || raw.match(/(\[[\s\S]*\])/);
  decisions = JSON.parse(match ? (match[1] || match[0]) : raw);
} catch(e) {
  decisions = [];
}

// Return only approve_and_reply actions
return decisions
  .filter(d => d.action === 'approve_and_reply' && d.reply)
  .map(d => ({ json: d }));
